<template>
  <div>
    <a-layout>
      <a-layout-content
        :style="{ background: '#fff', padding: '24px', margin: 0, minHeight: '280px' }"
      >
        <p>
          <a-form layout="inline" :model="param">
            <a-form-item>
              <a-button type="primary" @click="add()">
                新增
              </a-button>
            </a-form-item>
          </a-form>
        </p>

        <a-table
          v-if="level1.length > 0"
          :columns="columns"
          :row-key="record => record.id"
          :data-source="level1"
          :pagination="false"
          :loading="loading"
          :defaultExpandAllRows="true"
        >
          <template #bodyCell="{ column, record }">
            <template v-if="column.dataIndex === 'action'">
              <a-space size="small">
                <a-button type="primary" @click="edit(record)">
                  编辑
                </a-button>
                <a-popconfirm
                  title="删除后不可以恢复，确认删除?"
                  ok-text="是"
                  cancel-text="否"
                  @confirm="handleDelete(record.id)"
                >
                  <a-button danger>
                    删除
                  </a-button>
                </a-popconfirm>
              </a-space>
            </template>
          </template>
        </a-table>
      </a-layout-content>
    </a-layout>

    <!-- 弹窗：新增 / 编辑 -->
    <a-modal
      title="文档表单"
      v-model:open="modalVisible"
      :confirm-loading="modalLoading"
      width="800px"
      @ok="handleModalOk"
    >
      <a-form :model="doc" :label-col="{ span: 4 }" :wrapper-col="{ span: 20 }">
        <a-form-item label="名称">
          <a-input v-model:value="doc.name" placeholder="名称" />
        </a-form-item>

        <a-form-item label="父文档">
          <a-tree-select
            v-model:value="doc.parent"
            show-search
            style="width: 100%"
            :dropdown-style="{ maxHeight: '400px', overflow: 'auto' }"
            placeholder="请选择父文档"
            allow-clear
            tree-default-expand-all
            :tree-data="treeSelectData"
            tree-node-filter-prop="label"
            :field-names="{ children: 'children', label: 'name', key: 'id', value: 'id' }"
          />
        </a-form-item>

        <a-form-item label="排序">
          <a-input v-model:value="doc.sort" placeholder="顺序" />
        </a-form-item>

        <!-- wangEditor 富文本编辑器 -->
        <a-form-item label="内容">
          <div style="border: 1px solid #ccc; width: 100%;">
            <Toolbar
              style="border-bottom: 1px solid #ccc"
              :editor="editorRef"
              :defaultConfig="toolbarConfig"
              :mode="mode"
            />
            <Editor
              style="height: 400px; overflow-y: hidden;"
              :defaultConfig="editorConfig"
              :mode="mode"
              @onCreated="handleCreated"
            />
          </div>
        </a-form-item>
      </a-form>
    </a-modal>
  </div>
</template>

<script setup>
import axios from 'axios'
import { ref, onMounted } from 'vue'
import { useRoute } from 'vue-router'
import { message } from 'ant-design-vue'
import { Editor, Toolbar } from '@wangeditor/editor-for-vue'
import '@wangeditor/editor/dist/css/style.css'

const route = useRoute()
const param = ref({})
const loading = ref(false)
const level1 = ref([])
const treeSelectData = ref([])
const modalVisible = ref(false)
const modalLoading = ref(false)

// ---------- wangEditor ----------
const editorRef = ref(null)
const mode = ref('default')
const toolbarConfig = ref({})
const editorConfig = ref({
  placeholder: '请输入文档内容...'
})

const handleCreated = (editor) => {
  editorRef.value = editor
}

const columns = [
  { title: '名称', dataIndex: 'name' },
  { title: '操作', key: 'action', dataIndex: 'action' }
]

const doc = ref({
  id: null,
  ebookId: null,
  name: '',
  parent: 0,
  sort: 0,
  content: ''
})

// ---------- 树形结构构建 ----------
const buildTree = (list, parentId = 0) => {
  const pid = String(parentId)
  return list
    .filter(item => String(item.parent) === pid)
    .map(item => ({
      ...item,
      children: buildTree(list, item.id)
    }))
}

// ---------- 递归禁用节点 ----------
// eslint-disable-next-line no-unused-vars
const setDisable = (treeData, targetId) => {
  for (let i = 0; i < treeData.length; i++) {
    const node = treeData[i]
    if (String(node.id) === String(targetId)) {
      node.disabled = true
      if (node.children && node.children.length > 0) {
        setDisable(node.children, targetId)
      }
    } else {
      if (node.children && node.children.length > 0) {
        setDisable(node.children, targetId)
      }
    }
  }
}

// ---------- 递归获取所有子节点 ID ----------
const ids = []
const getDeleteIds = (treeData, targetId) => {
  for (let i = 0; i < treeData.length; i++) {
    const node = treeData[i]
    if (String(node.id) === String(targetId)) {
      ids.push(targetId)
      if (node.children && node.children.length > 0) {
        for (let j = 0; j < node.children.length; j++) {
          getDeleteIds(node.children, node.children[j].id)
        }
      }
    } else {
      if (node.children && node.children.length > 0) {
        getDeleteIds(node.children, targetId)
      }
    }
  }
}

// ---------- 数据查询 ----------
const handleQuery = () => {
  loading.value = true
  axios.get('/doc/all')
    .then((resp) => {
      loading.value = false
      const data = resp.data
      if (data.success) {
        level1.value = buildTree(data.content || [], 0)
      } else {
        message.error(data.message || '加载失败')
      }
    })
    .catch(() => {
      loading.value = false
      message.error('加载失败，请重试')
    })
}

// ---------- 新增 ----------
const add = () => {
  modalVisible.value = true
  const ebookId = route.query.ebookId || null
  doc.value = {
    id: null,
    ebookId: ebookId,
    name: '',
    parent: 0,
    sort: 0,
    content: ''
  }
  treeSelectData.value = JSON.parse(JSON.stringify(level1.value))
  treeSelectData.value.unshift({ id: 0, name: '无' })

  // 清空编辑器内容
  if (editorRef.value) {
    editorRef.value.setHtml('')
  }
}

// ---------- 编辑（查询内容） ----------
const edit = (record) => {
  modalVisible.value = true
  doc.value = {
    ...record,
    parent: Number(record.parent) || 0,
    sort: Number(record.sort) || 0,
    content: ''
  }

  // 查询文档内容，用 setHtml 填充到编辑器
  axios.get('/content/findContent/' + doc.value.id)
    .then((response) => {
      const data = response.data
      if (data.success && data.content) {
        if (editorRef.value) {
          editorRef.value.setHtml(data.content)
        }
      }
    })
    .catch(() => {})

  // 树选择：禁用当前节点及其子节点
  const treeCopy = JSON.parse(JSON.stringify(level1.value))
  setDisable(treeCopy, record.id)
  treeCopy.unshift({ id: 0, name: '无' })
  treeSelectData.value = treeCopy
}

// ---------- 删除 ----------
const handleDelete = (id) => {
  ids.length = 0
  getDeleteIds(level1.value, id)
  if (ids.length === 0) {
    message.warning('未找到要删除的节点')
    return
  }
  axios.get(`/doc/remove?ids=${ids.join(',')}`)
    .then((resp) => {
      if (resp.data.success) {
        message.success('删除成功')
        handleQuery()
      } else {
        message.error(resp.data.message || '删除失败')
      }
    })
    .catch(() => {
      message.error('删除失败，请重试')
    })
}

// ---------- 弹窗确定：保存文档 + 内容 ----------
const handleModalOk = () => {
  modalLoading.value = true

  // 获取富文本内容
  if (editorRef.value) {
    doc.value.content = editorRef.value.getHtml()
  }

  axios.post('/doc/save', doc.value)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        modalLoading.value = false
        modalVisible.value = false
        message.success('保存成功！')
        handleQuery()
      } else {
        modalLoading.value = false
        message.error(data.message || '操作失败')
      }
    })
    .catch(() => {
      modalLoading.value = false
      message.error('保存失败，请重试')
    })
}

onMounted(() => {
  handleQuery()
})
</script>

